Rule.Source:
    import sailpoint.object.Identity;
    import sailpoint.object.TaskDefinition;
    import sailpoint.object.Identity.CreateProcessingStep;
	import sailpoint.api.TaskManager;
    import org.apache.commons.logging.Log;
    import org.apache.commons.logging.LogFactory;

  	Log logger = LogFactory.getLog("Ascension-Rule-Persona-Management-Task");
  
  	String taskStatus = "Success";
  	String identityName = null;
  
  	TaskDefinition taskDefinition = context.getObjectByName(TaskDefinition.class,"Ascension Persona Remediation Task");  
    if(null!=taskDefinition)
    {
      //Get all the values from task input parameters
      identityName = taskDefinition.getString("identityName");
    }

  	/*
    The identity to be remediated may be in the Parent-Child relationship tree. 
    So if we address all these cases we should be good with Remediation process	
    1	As a Parent with no child identities
    2	As a Parent with 1 child identity
    3	As a Parent with multiple child identities
    4	As a Child with no siblings (only child in the tree)
    5	As a Child with siblings
    */
  
    Identity toBeRemediatedIdentity = context.getObjectByName(Identity.class,identityName);
	Map attributesMap = new HashMap();
	attributesMap.put("processTriggers",true);
  
  	if(null!=toBeRemediatedIdentity)
    {
	  setTriggeredEventSequence(identityName,"REMEDIATION");
      String personaType = toBeRemediatedIdentity.getAttribute("personaType");
      String internalId = toBeRemediatedIdentity.getAttribute("internalId");
      
      if(null!=personaType && !personaType.isEmpty() && null!=internalId && !internalId.isEmpty())
      {
        if("Primary".equalsIgnoreCase(personaType))
        {
          
          List childPersonaList = toBeRemediatedIdentity.getAttribute("childPersonas");
          if(null==childPersonaList || (null!=childPersonaList && childPersonaList.isEmpty()))
          {
            //Parent does not have any child identities
            //Clear personaType
            //Clear internalId
            //Remove parentPersonaName
            //Remove parentPersonaSID
            
            try
            {
               deleteIdentityLinksFromIIQ(context, identityName);

               removeBirthRightRolesFromIdentity(identityName);
               toBeRemediatedIdentity.setNeedsCreateProcessing(true,Identity.CreateProcessingStep.Trigger);
			   refreshIdentityCube(identityName,attributesMap);
            }
            catch(Exception e)
            {
            	logger.error(e.getMessage());
            }
            
            toBeRemediatedIdentity.removeAttribute("personaType");
            toBeRemediatedIdentity.removeAttribute("childPersonas");
            toBeRemediatedIdentity.removeAttribute("childPersonaNames");
            toBeRemediatedIdentity.removeAttribute("parentPersonaName");
            toBeRemediatedIdentity.removeAttribute("parentPersonaSID");
            toBeRemediatedIdentity.removeAttribute("internalId");
            toBeRemediatedIdentity.removeAttribute("samAccountName");
            
            context.saveObject(toBeRemediatedIdentity);
            context.commitTransaction();
            //comment decache //context.decache(toBeRemediatedIdentity);
            
            
            //Write Audit records to IIQ.
            String auditString1 = "Identity that is remediated: "+identityName;
            String auditString2 = "Persona type: "+personaType+ ".This identity does not have any child personas. This is the only identity persona in the tree.";
            String auditString3 = "Deleting the birthright links and roles for the identity: "+identityName;
            writeAuditRecordToIIQ("PersonaRemediation",auditString1, auditString2,auditString3,identityName,"Persona Remediation");
          }
          
          else if(null!=childPersonaList &&childPersonaList.size()>0)
          {
            //one or more child identities present.
            List childIdentitiesList = getChildIdentities(childPersonaList);
			if(childIdentitiesList == null){
				childIdentitiesList = new ArrayList();
			}
            String newParent = null;
            boolean priorityActiveParentFound = false;
            boolean priorityInActiveParentFound = false;
            
            //SEARCH FOR ACTIVE CHILD - BASED ON PRIORITY
            //Priority 1 - Search EmployeeProfile Child.
            for(String childIdenName :childIdentitiesList)
            {
              Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
              boolean isActive = getIdentityStatus(childIdenName);
              if(null!=tempIden && isActive)
              {
                String tempIdentityType = tempIden.getAttribute("identityType");
                if(null==tempIdentityType)
                {
                	 tempIdentityType = getProfileType(childIdenName);
                }
                if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("EmployeePersona"))
                {
                  newParent = childIdenName;
                  priorityActiveParentFound = true;
                  break;
                }
                //comment decache //context.decache(tempIden);
              }
            }
            
            if(!priorityActiveParentFound)
            {
              //Priority 2 - Search ProviderProfile Child.
              for(String childIdenName :childIdentitiesList)
              {
                Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
                boolean isActive = getIdentityStatus(childIdenName);
                if(null!=tempIden && isActive)
                {
                  String tempIdentityType = tempIden.getAttribute("identityType");
                  if(null==tempIdentityType)
                  {
                     tempIdentityType = getProfileType(childIdenName);
                  }
                  if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("ProviderPersona"))
                  {
                    newParent = childIdenName;
                    priorityActiveParentFound = true;
                    break;
                  }
                  //comment decache //context.decache(tempIden);
                }
              }
            }

            if(!priorityActiveParentFound)
            {
              //Priority 3 - Search NHRCProfile Child.
              for(String childIdenName :childIdentitiesList)
              {
                Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
                boolean isActive = getIdentityStatus(childIdenName);
                if(null!=tempIden && isActive)
                {
                  String tempIdentityType = tempIden.getAttribute("identityType");
                  if(null==tempIdentityType)
                  {
                     tempIdentityType = getProfileType(childIdenName);
                  }
                  if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("NonHRContractorPersona"))
                  {
                    newParent = childIdenName;
                    priorityActiveParentFound = true;
                    break;
                  }
                  //comment decache //context.decache(tempIden);
                }
              }
            }

            if(!priorityActiveParentFound)
            {
              //Priority 4 - Search OtherProfile Child.
              for(String childIdenName :childIdentitiesList)
              {
                Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
                boolean isActive = getIdentityStatus(childIdenName);
                if(null!=tempIden && isActive)
                {
                  String tempIdentityType = tempIden.getAttribute("identityType");
                  if(null==tempIdentityType)
                  {
                     tempIdentityType = getProfileType(childIdenName);
                  }
                  if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("OtherPersona"))
                  {
                    newParent = childIdenName;
                    priorityActiveParentFound = true;
                    break;
                  }
                  //comment decache //context.decache(tempIden);
                }
              }
            }
        			
        		
            if(!priorityActiveParentFound)
            {
              //SEARCH FOR INACTIVE CHILD BASED ON PRIORITY.
              for(String childIdenName :childIdentitiesList)
              {
                Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
                boolean isActive = getIdentityStatus(childIdenName);
                if(null!=tempIden && !isActive)
                {
                  String tempIdentityType = tempIden.getAttribute("identityType");
                  if(null==tempIdentityType)
                  {
                     tempIdentityType = getProfileType(childIdenName);
                  }
                  if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("EmployeePersona"))
                  {
                    newParent = childIdenName;
                    priorityActiveParentFound = true;
                    break;
                  }
                  //comment decache //context.decache(tempIden);
                }
              }
              
              if(!priorityInActiveParentFound)
            	{
              		for(String childIdenName :childIdentitiesList)
                  {
                    Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
                    boolean isActive = getIdentityStatus(childIdenName);
                    if(null!=tempIden && !isActive)
                    {
                      String tempIdentityType = tempIden.getAttribute("identityType");
                      if(null==tempIdentityType)
                      {
                         tempIdentityType = getProfileType(childIdenName);
                      }
                      if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("ProviderPersona"))
                      {
                        newParent = childIdenName;
                        priorityActiveParentFound = true;
                        break;
                      }
                      //comment decache //context.decache(tempIden);
                    }
                  }
              }
              
              if(!priorityInActiveParentFound)
            	{
              		for(String childIdenName :childIdentitiesList)
                  {
                    Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
                    boolean isActive = getIdentityStatus(childIdenName);
                    if(null!=tempIden && !isActive)
                    {
                      String tempIdentityType = tempIden.getAttribute("identityType");
                      if(null==tempIdentityType)
                      {
                         tempIdentityType = getProfileType(childIdenName);
                      }
                      if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("NonHRContractorPersona"))
                      {
                        newParent = childIdenName;
                        priorityActiveParentFound = true;
                        break;
                      }
                      //comment decache //context.decache(tempIden);
                    }
                  }
              }
              
              if(!priorityInActiveParentFound)
            	{
              		for(String childIdenName :childIdentitiesList)
                  {
                    Identity tempIden = context.getObjectByName(Identity.class,childIdenName);
                    boolean isActive = getIdentityStatus(childIdenName);
                    if(null!=tempIden && !isActive)
                    {
                      String tempIdentityType = tempIden.getAttribute("identityType");
                      if(null==tempIdentityType)
                      {
                         tempIdentityType = getProfileType(childIdenName);
                      }
                      if(null!=tempIdentityType && tempIdentityType.equalsIgnoreCase("OtherPersona"))
                      {
                        newParent = childIdenName;
                        priorityActiveParentFound = true;
                        break;
                      }
                      //comment decache //context.decache(tempIden);
                    }
                  }
              }
              
            }
            
            
             //Write Audit records to IIQ.
            String auditString1 = "New Parent (Primary) Identity: "+newParent;
            String auditString2 = "Old Parent (Primary) Identity that was remediated: "+identityName;
            String auditString3 = "Birthright links and roles moved from : "+identityName + " to "+newParent;
            writeAuditRecordToIIQ("PersonaRemediation" ,auditString1, auditString2,auditString3,identityName,"Persona Remediation");
        
            Identity newParentIdentity = context.getObjectByName(Identity.class,newParent);
            if(null!=newParentIdentity)
            {
              newParentIdentity.setAttribute("personaType","Primary");
              newParentIdentity.removeAttribute("parentPersonaName");
              newParentIdentity.removeAttribute("parentPersonaSID");

              childPersonaList.remove(newParentIdentity.getAttribute("internalId"));
              childPersonaList.remove(internalId);//id of the unlinked identity

              context.saveObject(newParentIdentity);
              context.commitTransaction();
              //comment decache //context.decache(newParentIdentity);

              Identity newParentIden = context.getObjectByName(Identity.class,newParent);
              if(null==childPersonaList && (null!=childPersonaList && childPersonaList.isEmpty())) 
              {
                newParentIden.removeAttribute("childPersonas");
              	newParentIden.removeAttribute("childPersonaNames");
              }
              else
              {
                newParentIden.setAttribute("childPersonas", childPersonaList);
                List childNamesStr = getChildIdentities(childPersonaList);
                newParentIden.setAttribute("childPersonaNames", childNamesStr);
              }

              context.saveObject(newParentIden);
              context.commitTransaction();
              //comment decache //context.decache(newParentIden);

              //Update parent identities in secondary identities
              updateParentPersonaAttributesInSecondaryIdentities(childPersonaList,newParent);

              try
              {
              	toBeRemediatedIdentity.setNeedsCreateProcessing(true,Identity.CreateProcessingStep.Trigger);
				refreshIdentityCube(identityName,attributesMap);
              }
              catch(Exception e)
              {
              	logger.error(e.getMessage());
              }

              toBeRemediatedIdentity.removeAttribute("personaType");
              toBeRemediatedIdentity.removeAttribute("childPersonas");
              toBeRemediatedIdentity.removeAttribute("childPersonaNames");
              toBeRemediatedIdentity.removeAttribute("parentPersonaName");
              toBeRemediatedIdentity.removeAttribute("parentPersonaSID");
              toBeRemediatedIdentity.removeAttribute("internalId");
              toBeRemediatedIdentity.removeAttribute("samAccountName");

              context.saveObject(toBeRemediatedIdentity);
              context.commitTransaction();
              //comment decache //context.decache(toBeRemediatedIdentity);

              //Move Links and Birthright Roles
              boolean linkedMovedSuccess = false;
              try
              {
                moveIdentityLinks(identityName,newParent);
                linkedMovedSuccess = true;
              }
              catch(Exception e)
              {
                logger.error("Error occurred while moving links.Details:\n"+e.getMessage());
              }

              
              boolean setProtectedFlag = false;
              List assignedRolesList = getBirthRightAssignedRolesForIdentity(identityName);
              removeBirthRightRolesFromIdentity(identityName);
              if(linkedMovedSuccess)
              {
                addBirthRightRolesToIdentity(newParent,assignedRolesList);
              }
              
              //Username rename scenario logic
              Identity latestParentIden = context.getObjectByName(Identity.class,newParent);
              Identity latestChildIden = context.getObjectByName(Identity.class,identityName); //toBeRemediated Identity
              
              String initialName = latestChildIden.getAttribute("initialName");
              boolean nameChangeNeededForNewParent = checkIfUserNameNeedsToBeChanged(newParent);
        
        		  if(null!=initialName && nameChangeNeededForNewParent)
        		  {
                String samName = latestChildIden.getName();
                String initName = initialName;
                String inIdenName = latestParentIden.getName();

                latestChildIden.setName(initName);

                try
                {
                  context.saveObject(latestChildIden);
                  context.commitTransaction();
                  //comment decache //context.decache(latestChildIden);
                }
                catch(Exception e)
                {
                  logger.error(e.getMessage());
                }

                latestParentIden.setName(samName);
                latestParentIden.setAttribute("initialName",inIdenName);

                try
                {
                  context.saveObject(latestParentIden);
                  context.commitTransaction();
                  //comment decache //context.decache(latestParentIden);
                }
                catch(Exception e)
                {
                  logger.error(e.getMessage());
                }

                Identity latestChildIdentity = context.getObjectByName(Identity.class,initName);
                Identity latestParentIdentity = context.getObjectByName(Identity.class,samName);
                
                List chdPersonaList = latestParentIdentity.getAttribute("childPersonas");
                List childNamesStr = getChildIdentities(chdPersonaList);
                latestParentIdentity.setAttribute("childPersonaNames", childNamesStr);
                
                //Update primary identities details in child identities
                updateParentPersonaAttributesInSecondaryIdentities(chdPersonaList,samName);

                try
                {
                  context.saveObject(latestParentIdentity);
                  context.commitTransaction();
                  //comment decache //context.decache(latestParentIdentity);
                }
                catch(Exception e)
                {
                  logger.error(e.getMessage());
                }

                if(setProtectedFlag)
                {
                  Identity tempChildIden = context.getObjectByName(Identity.class,initialName);
                  tempChildIden.setProtected(false);
                  context.saveObject(tempChildIden);
                  context.commitTransaction();
                  //comment decache //context.decache(tempChildIden);
                }
                
                if(null!=initialName)
                {
                  String auditString1 = "Based on the username move criteria, username moved from Remediated Identity to New Parent Identity";
                  String auditString2 = "Remediated identity username now is:"+initialName + " from earlier username: "+identityName;
                  String auditString3 = "New Parent identity username now is:"+ samName+ " from earlier username: "+newParent;
                  writeAuditRecordToIIQ("PersonaUsernameMove",auditString1, auditString2,auditString3,samName,"Persona Remediation");
                }
              }
             
            }//end null noteq parentiden
          }//elif end
        }//end primary
        else if("Child".equalsIgnoreCase(personaType))
        {
          String parentPersonaName =  toBeRemediatedIdentity.getAttribute("parentPersonaName");
          if(null!=parentPersonaName && !parentPersonaName.isEmpty())
          {
          	Identity parentIdentity = context.getObjectByName(Identity.class,parentPersonaName);
            
            List childPersonaList = parentIdentity.getAttribute("childPersonas");
            
            if(null!=childPersonaList && childPersonaList.size()>0)
            {
                //The to be remediated identity is either a single child in the tree or is having siblings.
                toBeRemediatedIdentity.removeAttribute("personaType");
                toBeRemediatedIdentity.removeAttribute("childPersonas");
                toBeRemediatedIdentity.removeAttribute("childPersonaNames");
                toBeRemediatedIdentity.removeAttribute("parentPersonaName");
                toBeRemediatedIdentity.removeAttribute("parentPersonaSID");
                toBeRemediatedIdentity.removeAttribute("internalId");
                toBeRemediatedIdentity.removeAttribute("samAccountName");
              	toBeRemediatedIdentity.removeAttribute("initialName");
                
                try
                {
                	toBeRemediatedIdentity.setNeedsCreateProcessing(true,Identity.CreateProcessingStep.Trigger);
					refreshIdentityCube(identityName,attributesMap);
                }
                catch(Exception e)
                {
                  logger.error(e.getMessage());
                }
                
              
              	//Write Audit records to IIQ.
                String auditString1 = "Identity that is remediated: "+toBeRemediatedIdentity.getName();
                String auditString2 = "Persona type: "+personaType;
                String auditString3 = "Unlinking the identity: "+ toBeRemediatedIdentity.getName() +" and updating the Parent Identity: "+parentIdentity.getName();
                writeAuditRecordToIIQ("PersonaRemediation",auditString1,auditString2,auditString3,toBeRemediatedIdentity.getName(),"Persona Remediation");
              
              
                context.saveObject(toBeRemediatedIdentity);
                context.commitTransaction();
                //comment decache //context.decache(toBeRemediatedIdentity);
                
                List childAttributesSIDList = parentIdentity.getAttribute("childPersonas");
                List childAttributesNamesList = parentIdentity.getAttribute("childPersonaNames");
                
				if(!Util.isEmpty( childAttributesSIDList )){
					childAttributesSIDList.remove(internalId);
                }
				if(!Util.isEmpty( childAttributesNamesList )){
					childAttributesNamesList.remove(identityName);
				}
				if(null==childAttributesSIDList || (childAttributesSIDList!=null && childAttributesSIDList.isEmpty()))
                {
                  parentIdentity.removeAttribute("childPersonas");
                	parentIdentity.removeAttribute("childPersonaNames");
                }
                else
                {
                  parentIdentity.setAttribute("childPersonas",childAttributesSIDList);
                  parentIdentity.setAttribute("childPersonaNames",childAttributesNamesList);
                }
				
				context.saveObject(parentIdentity);
                context.commitTransaction();
                //comment decache //context.decache(parentIdentity);
              
            }//chdperslist gt 0
          }//parentPersonaName not empty
        }//if child
      }//persona type not null
    }//identity not null
   	return taskStatus;
